import{_ as d,o as a,c as r,ag as e}from"./chunks/framework.Vng7Hdlh.js";const u=JSON.parse('{"title":"16. 店舗設定","description":"","frontmatter":{},"headers":[],"relativePath":"internal/features/16-settings.md","filePath":"internal/features/16-settings.md"}'),h={name:"internal/features/16-settings.md"};function o(l,t,i,n,s,b){return a(),r("div",null,[...t[0]||(t[0]=[e('<h1 id="_16-店舗設定" tabindex="-1">16. 店舗設定 <a class="header-anchor" href="#_16-店舗設定" aria-label="Permalink to &quot;16. 店舗設定&quot;">​</a></h1><p>管理ダッシュボードの「店舗設定」タブでは、店舗の各種設定を行います。マネージャー以上のロールで利用できます。</p><h2 id="_16-1-サブタブ一覧" tabindex="-1">16.1 サブタブ一覧 <a class="header-anchor" href="#_16-1-サブタブ一覧" aria-label="Permalink to &quot;16.1 サブタブ一覧&quot;">​</a></h2><table tabindex="0"><thead><tr><th>サブタブ</th><th>説明</th></tr></thead><tbody><tr><td>営業設定</td><td>営業日区切り・税率・ラストオーダー等</td></tr><tr><td>KDSステーション</td><td>KDSのステーション設定</td></tr><tr><td>スタッフ管理</td><td>自店舗のスタッフアカウント管理</td></tr><tr><td>監査ログ</td><td>操作履歴の閲覧</td></tr><tr><td>領収書設定</td><td>レシートの表示内容設定</td></tr></tbody></table><hr><h2 id="_16-2-営業設定" tabindex="-1">16.2 営業設定 <a class="header-anchor" href="#_16-2-営業設定" aria-label="Permalink to &quot;16.2 営業設定&quot;">​</a></h2><h3 id="営業基本設定" tabindex="-1">営業基本設定 <a class="header-anchor" href="#営業基本設定" aria-label="Permalink to &quot;営業基本設定&quot;">​</a></h3><table tabindex="0"><thead><tr><th>設定項目</th><th>初期値</th><th>説明</th></tr></thead><tbody><tr><td>営業日区切り時刻</td><td>05:00</td><td>この時刻でレポートの「1日」が区切られます。深夜営業の場合、翌日の5:00までが前日の売上として集計されます</td></tr><tr><td>税率（%）</td><td>10</td><td>店内飲食の標準消費税率</td></tr><tr><td>注文上限数</td><td>10</td><td>セルフオーダーでの1回の注文の品目上限数</td></tr><tr><td>注文上限金額</td><td>¥30,000</td><td>セルフオーダーでの1回の注文の金額上限</td></tr><tr><td>ラストオーダー時刻</td><td>—</td><td>自動ラストオーダーの時刻。設定すると、この時刻にセルフオーダーの新規注文が自動ブロックされます</td></tr></tbody></table><h3 id="レジ設定" tabindex="-1">レジ設定 <a class="header-anchor" href="#レジ設定" aria-label="Permalink to &quot;レジ設定&quot;">​</a></h3><table tabindex="0"><thead><tr><th>設定項目</th><th>初期値</th><th>説明</th></tr></thead><tbody><tr><td>レジ開け初期金額</td><td>¥30,000</td><td>レジ開け時のデフォルトつり銭準備金</td></tr><tr><td>過不足閾値</td><td>¥500</td><td>この金額を超える過不足がある場合、レジレポートで警告表示</td></tr><tr><td>現金</td><td>ON</td><td>現金決済の有効/無効</td></tr><tr><td>クレジットカード</td><td>ON</td><td>カード決済の有効/無効</td></tr><tr><td>QRコード</td><td>ON</td><td>QR決済の有効/無効</td></tr></tbody></table><h3 id="レシート設定" tabindex="-1">レシート設定 <a class="header-anchor" href="#レシート設定" aria-label="Permalink to &quot;レシート設定&quot;">​</a></h3><table tabindex="0"><thead><tr><th>設定項目</th><th>説明</th></tr></thead><tbody><tr><td>店舗名</td><td>レシートに印刷する店舗名</td></tr><tr><td>住所</td><td>レシートに印刷する住所</td></tr><tr><td>電話番号</td><td>レシートに印刷する電話番号</td></tr><tr><td>フッターテキスト</td><td>レシート下部に印刷するメッセージ（複数行対応）</td></tr></tbody></table><h3 id="googleレビュー設定" tabindex="-1">Googleレビュー設定 <a class="header-anchor" href="#googleレビュー設定" aria-label="Permalink to &quot;Googleレビュー設定&quot;">​</a></h3><table tabindex="0"><thead><tr><th>設定項目</th><th>説明</th></tr></thead><tbody><tr><td>Google Place ID</td><td>GoogleマップのプレイスID。設定すると、お客さんが高評価（4〜5つ星）を付けた際にGoogleレビューページへのリンクが表示されます</td></tr></tbody></table><h3 id="テイクアウト設定" tabindex="-1">テイクアウト設定 <a class="header-anchor" href="#テイクアウト設定" aria-label="Permalink to &quot;テイクアウト設定&quot;">​</a></h3><p>テイクアウト機能の各設定については「9. テイクアウト管理」を参照してください。</p><h3 id="外観カスタマイズ" tabindex="-1">外観カスタマイズ <a class="header-anchor" href="#外観カスタマイズ" aria-label="Permalink to &quot;外観カスタマイズ&quot;">​</a></h3><table tabindex="0"><thead><tr><th>設定項目</th><th>説明</th></tr></thead><tbody><tr><td>テーマカラー</td><td>セルフオーダー画面のメインカラー。カラーピッカーまたはHEX値で指定。デフォルト：#ff6f00（セルフオーダー）、#2196F3（テイクアウト）</td></tr><tr><td>表示名</td><td>ヘッダーに表示するブランド名</td></tr><tr><td>ロゴ画像URL</td><td>ヘッダーに表示するロゴ画像のURL。ライブプレビュー付き</td></tr></tbody></table><hr><h2 id="_16-3-kdsステーション" tabindex="-1">16.3 KDSステーション <a class="header-anchor" href="#_16-3-kdsステーション" aria-label="Permalink to &quot;16.3 KDSステーション&quot;">​</a></h2><p>KDSのステーション設定については「7.10 KDSステーションの設定」を参照してください。</p><hr><h2 id="_16-4-スタッフ管理" tabindex="-1">16.4 スタッフ管理 <a class="header-anchor" href="#_16-4-スタッフ管理" aria-label="Permalink to &quot;16.4 スタッフ管理&quot;">​</a></h2><p>マネージャーは自店舗のスタッフアカウントを管理できます。</p><h3 id="スタッフの作成" tabindex="-1">スタッフの作成 <a class="header-anchor" href="#スタッフの作成" aria-label="Permalink to &quot;スタッフの作成&quot;">​</a></h3><table tabindex="0"><thead><tr><th>フィールド</th><th>種類</th><th>必須</th><th>説明</th></tr></thead><tbody><tr><td>表示名</td><td>テキスト</td><td>✅</td><td>—</td></tr><tr><td>ユーザー名</td><td>テキスト</td><td>✅</td><td>ログインID</td></tr><tr><td>パスワード</td><td>パスワード</td><td>✅</td><td>初期パスワード</td></tr></tbody></table><h3 id="スタッフの編集" tabindex="-1">スタッフの編集 <a class="header-anchor" href="#スタッフの編集" aria-label="Permalink to &quot;スタッフの編集&quot;">​</a></h3><ul><li>表示名の変更</li><li>パスワードの変更</li><li>有効/無効の切替</li></ul><div class="warning custom-block"><p class="custom-block-title">マネージャーの制限</p><p>マネージャーが管理できるのは自分の所属店舗のスタッフのみです。他店舗のスタッフや他のマネージャーのアカウントは変更できません。他店舗のスタッフ管理はオーナーダッシュボードの「ユーザー管理」タブから行います。</p></div><hr><h2 id="_16-5-監査ログ" tabindex="-1">16.5 監査ログ <a class="header-anchor" href="#_16-5-監査ログ" aria-label="Permalink to &quot;16.5 監査ログ&quot;">​</a></h2><p>店舗内の全操作の履歴を閲覧できます。</p><h3 id="アクティブセッション管理" tabindex="-1">アクティブセッション管理 <a class="header-anchor" href="#アクティブセッション管理" aria-label="Permalink to &quot;アクティブセッション管理&quot;">​</a></h3><p>監査ログ画面では、現在アクティブなセッション（ログイン中の端末）も確認できます。</p><table tabindex="0"><thead><tr><th>表示情報</th><th>説明</th></tr></thead><tbody><tr><td>端末情報</td><td>ブラウザ/OS</td></tr><tr><td>IPアドレス</td><td>—</td></tr><tr><td>ログイン日時</td><td>—</td></tr><tr><td>最終操作日時</td><td>—</td></tr></tbody></table><p>不審なセッションや退勤後のログアウト忘れに対して、「ログアウト」ボタンでリモートログアウトが可能です。</p><hr><h2 id="_16-6-設定変更の反映タイミング" tabindex="-1">16.6 設定変更の反映タイミング <a class="header-anchor" href="#_16-6-設定変更の反映タイミング" aria-label="Permalink to &quot;16.6 設定変更の反映タイミング&quot;">​</a></h2><p>設定変更は保存後すぐに反映されます。ただし、以下の点に注意してください。</p><ul><li><strong>セルフオーダー画面：</strong> お客さんが画面をリロードするか、メニューバージョンチェック（3分間隔）で更新されます</li><li><strong>KDS画面：</strong> 次のポーリング（3秒間隔）で反映されます</li><li><strong>ハンディPOS：</strong> 次のメニューバージョンチェック（3分間隔）で反映されます</li><li><strong>レジ画面：</strong> 次のポーリングで反映されます</li></ul>',40)])])}const _=d(h,[["render",o]]);export{u as __pageData,_ as default};
